// frontend/src/components/Layout.js
import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// ── Images are in src/components/ (confirmed from file tree screenshot)
// Layout.js is also in src/components/ so we use './' (same folder)
import pic3 from '../components/lightmode.jpg';
import pic4 from '../components/darkmode.png';
import pic5 from '../components/gmail.png';
import pic6 from '../components/facebook.png';

const Layout = ({ children }) => {
  const [isDarkMode, setIsDarkMode] = useState(
    () => localStorage.getItem('theme') === 'dark'
  );
  const { user, logout } = useAuth();
  const location = useLocation();
  const navigate  = useNavigate();

  useEffect(() => {
    document.body.classList.toggle('dark-mode', isDarkMode);
    localStorage.setItem('theme', isDarkMode ? 'dark' : 'light');
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(prev => !prev);
  const isActive = (path) => location.pathname === path ? 'active' : '';
  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <div className={isDarkMode ? 'dark-theme-wrapper' : 'light-theme-wrapper'}>

      {/* ── Header ── */}
      <header>
        <h1>&#128506; MUSEUM JOURNAL</h1>
        <div
          className="mode-toggle"
          onClick={toggleDarkMode}
          style={{
            cursor:         'pointer',
            position:       'absolute',
            top:            '15px',
            right:          '15px',
            zIndex:         10,
            background:     'rgba(255, 255, 255, 0.2)',
            borderRadius:   '50%',
            padding:        '8px',
            width:          '48px',
            height:         '48px',
            display:        'flex',
            alignItems:     'center',
            justifyContent: 'center',
            transition:     'background 0.2s ease, transform 0.2s ease',
          }}
          onMouseEnter={e => {
            e.currentTarget.style.transform  = 'scale(1.1)';
            e.currentTarget.style.background = 'rgba(255,255,255,0.35)';
          }}
          onMouseLeave={e => {
            e.currentTarget.style.transform  = 'scale(1)';
            e.currentTarget.style.background = 'rgba(255,255,255,0.2)';
          }}
        >
          <img
            src={isDarkMode ? pic4 : pic3}
            alt={isDarkMode ? 'Switch to light mode' : 'Switch to dark mode'}
            id="mode-icon"
            style={{
              width:   '30px',
              height:  '30px',
              display: 'block',
              filter:  'invert(1)',
            }}
          />
        </div>
      </header>

      {/* ── Navigation ── */}
      <nav className="horizontal-nav">
        <ul>
          <li><Link to="/home"    className={isActive('/home')}>Home</Link></li>
          <li><Link to="/about"   className={isActive('/about')}>About Us</Link></li>
          <li><Link to="/contact" className={isActive('/contact')}>Contact Us</Link></li>

          {/* Logged OUT */}
          {!user && (
            <>
              <li><Link to="/register" className={isActive('/register')}>Register</Link></li>
              <li><Link to="/login"    className={isActive('/login')}>Login</Link></li>
            </>
          )}

          {/* Logged IN */}
          {user && (
            <>
              <li><Link to="/create-post" className={isActive('/create-post')}>Write Post</Link></li>
              <li><Link to="/profile"     className={isActive('/profile')}>Profile</Link></li>
              {user.role === 'admin' && (
                <li><Link to="/admin" className={isActive('/admin')}>Admin</Link></li>
              )}
              <li>
                <button className="nav-logout-btn" onClick={handleLogout}>
                  Logout ({user.name})
                </button>
              </li>
            </>
          )}
        </ul>
      </nav>

      {/* ── Page Content ── */}
      <main>{children}</main>

      {/* ── Footer ── */}
      <footer className="footer">
        <div className="footer-logos">
          <div className="footer-item">
            <img
              src={pic5}
              alt="Gmail"
              className="footer-logo"
              style={{
                width:        '28px',
                height:       '28px',
                borderRadius: '50%',
                objectFit:    'cover',
                border:       'none',
                margin:       '0',
                padding:      '2px',
              }}
            />
            <span>maicadoctolero@gmail.com</span>
          </div>
          <div className="footer-item">
            <img
              src={pic6}
              alt="Facebook"
              className="footer-logo"
              style={{
                width:        '28px',
                height:       '28px',
                borderRadius: '6px',
                objectFit:    'cover',
                border:       'none',
                margin:       '0',
                padding:      '2px',
              }}
            />
            <span>maicadoctolero@facebook.com</span>
          </div>
        </div>
        <p>© All Rights Reserved 2026</p>
      </footer>

    </div>
  );
};

export default Layout;
